// Build Arbeitsagentur search queries
const queries = [
  { was: 'Python Developer', wo: 'Hamburg', umkreis: 50 },
  { was: 'Backend Engineer', wo: 'Hamburg', umkreis: 50 },
  { was: 'Data Engineer', wo: 'Hamburg', umkreis: 50 },
  { was: 'Software Engineer Python', wo: 'Hamburg', umkreis: 50 },
  { was: 'Python Developer', wo: 'Berlin', umkreis: 25 },
  { was: 'Backend Engineer', wo: 'Berlin', umkreis: 25 },
];
return queries.map(q => ({ json: q }));

// Flatten + normalize Arbeitsagentur results
const allItems = [];
for (const item of $input.all()) {
  const jobs = item.json?.stellenangebote || [];
  for (const job of jobs) {
    allItems.push({
      json: {
        source: 'arbeitsagentur',
        external_id: job.hashId || job.refnr || '',
        url: `https://www.arbeitsagentur.de/jobsuche/suche?id=${job.hashId || ''}`,
        title: job.titel || '',
        company: job.arbeitgeber || '',
        location: job.arbeitsort?.ort || '',
        hash_id: job.hashId || '',
        needs_detail: true
      }
    });
  }
}
// Deduplicate within batch
const seen = new Set();
const unique = allItems.filter(item => {
  if (seen.has(item.json.external_id)) return false;
  seen.add(item.json.external_id);
  return true;
});
return unique.length > 0 ? unique : [{ json: { _empty: true } }];

// Merge AA detail into normalized format
const d = $input.first().json;
const desc = d.stellenbeschreibung || d.beschreibung || d.freitextFeld || JSON.stringify(d);
return [{
  json: {
    source: 'arbeitsagentur',
    external_id: d.hashId || d.refnr || '',
    url: `https://www.arbeitsagentur.de/jobsuche/suche?id=${d.hashId || ''}`,
    title: d.titel || d.beruf || '',
    company: d.arbeitgeber?.name || d.arbeitgeber || '',
    location: d.arbeitsort?.ort || d.arbeitsorte?.[0]?.ort || '',
    description: typeof desc === 'string' ? desc.substring(0, 5000) : JSON.stringify(desc).substring(0, 5000),
    needs_parsing: false
  }
}];

// Fetch up to 3 pages from Arbeitnow API (with 5s delay between pages)
const allData = [];
const maxPages = 3;
for (let page = 1; page <= maxPages; page++) {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://www.arbeitnow.com/api/job-board-api?page=${page}`,
    timeout: 15000
  });
  const data = resp.data || [];
  allData.push(...data);
  const lastPage = resp.meta?.last_page || 1;
  if (page >= lastPage) break;
  if (page < maxPages) await new Promise(r => setTimeout(r, 5000));
}
return [{ json: { data: allData } }];

// Filter & normalize Arbeitnow results
const data = $input.first().json?.data || [];
const titleKw = ['python','backend','back-end','data engineer','software engineer','platform engineer','api developer'];
const locKw = ['hamburg','berlin','germany','remote','deutschland'];
const weekAgo = Date.now() - 7*24*60*60*1000;

const filtered = data.filter(job => {
  const t = (job.title||'').toLowerCase();
  const l = (job.location||'').toLowerCase();
  const created = new Date(job.created_at*1000||job.created_at).getTime();
  return titleKw.some(k=>t.includes(k)) && (locKw.some(k=>l.includes(k))||job.remote) && created>weekAgo;
});

const seen = new Set();
const unique = filtered.filter(j => {
  const k = j.slug||j.url||j.title;
  if (seen.has(k)) return false;
  seen.add(k);
  return true;
});

return unique.length > 0
  ? unique.map(j => ({ json: {
      source: 'arbeitnow',
      external_id: j.slug||'',
      url: j.url||`https://www.arbeitnow.com/view/${j.slug}`,
      title: j.title||'',
      company: j.company_name||'',
      location: j.location||'',
      description: (j.description||'').substring(0,5000),
      tags: j.tags||[],
      remote: j.remote||false,
      needs_parsing: false
    }}))
  : [{ json: { _empty: true } }];

// Validate bookmarklet input
const body = $input.first().json.body || $input.first().json;
const url = body.url || '';
const title = body.title || '';
const notes = body.notes || '';

if (!url) throw new Error('No URL provided');

return [{
  json: {
    source: 'manual',
    external_id: url,
    url: url,
    title: title,
    notes: notes,
    needs_parsing: true
  }
}];

// Write HTML to temp file for parse script
const fs = require('fs');
const os = require('os');
const html = $input.first().json.data || $input.first().json.body || '';
const tmpFile = `${os.tmpdir()}/job_parse_${Date.now()}.html`;
fs.writeFileSync(tmpFile, typeof html === 'string' ? html : JSON.stringify(html));
return [{ json: { ...$('BM: Validate Input').first().json, tmpFile } }];

// Merge parsed data with original webhook info
const stdout = $input.first().json.stdout || '{}';
let parsed;
try { parsed = JSON.parse(stdout); } catch(e) { parsed = { error: 'parse failed' }; }
const original = $('BM: Validate Input').first().json;

return [{
  json: {
    source: 'manual',
    external_id: original.url,
    url: original.url,
    title: parsed.title || original.title || '',
    company: parsed.company || '',
    location: parsed.location || '',
    description: parsed.description || '',
    tech_stack: parsed.tech_stack || [],
    language_requirements: parsed.language_requirements || null,
    notes: original.notes || '',
    needs_parsing: false
  }
}];

// All paths converge here — deduplicate by URL across sources
const seen = new Set();
const items = $input.all().filter(item => {
  const url = item.json?.url;
  if (!url || seen.has(url)) return false;
  seen.add(url);
  return true;
});
return items.length > 0 ? items : [{ json: { _empty: true } }];

// If Sheet returned a matching row, it's a duplicate
const results = $input.all();
const isDuplicate = results.length > 0 && results[0].json?.['Job URL'];
const jobData = $('Merge All Sources').first().json;

if (isDuplicate) {
  return [{ json: { _duplicate: true } }];
}
return [{ json: { _duplicate: false, ...jobData } }];

// Prepare job data as JSON string and write to temp file
const fs = require('fs');
const os = require('os');
const job = $input.first().json;
const jobStr = JSON.stringify({
  title: job.title || '',
  company: job.company || '',
  location: job.location || '',
  description: job.description || '',
  tech_stack: job.tech_stack || [],
  language_requirements: job.language_requirements || null,
  tags: job.tags || [],
  url: job.url || ''
}, null, 2);

const tmpFile = `${os.tmpdir()}/job_filter_${Date.now()}.json`;
fs.writeFileSync(tmpFile, jobStr);

return [{ json: { ...job, _filterInput: tmpFile } }];

// Parse filter result from Claude
const stdout = $input.first().json.stdout || '{}';
const stderr = $input.first().json.stderr || '';
let assessment;
let parseError = false;
try {
  assessment = JSON.parse(stdout);
  if (assessment.error) parseError = true;
} catch(e) {
  parseError = true;
  assessment = { fit_score: 0, decision: 'SKIP', cv_variant: 'software', hard_blockers: ['Claude parse error'], reasoning: stdout.substring(0,200) };
}

const jobData = $('Filter: Prep Input').first().json;
delete jobData._filterInput;

return [{
  json: {
    ...jobData,
    assessment,
    _filterError: parseError,
    _filterStderr: stderr.substring(0, 500),
    fit_score: assessment.fit_score || 0,
    decision: assessment.decision || 'SKIP',
    cv_variant: assessment.cv_variant || 'software',
    hard_blockers: (assessment.hard_blockers || []).join('; '),
    strong_matches: (assessment.strong_matches || []).join('; '),
    reasoning: assessment.reasoning || ''
  }
}];

// Prepare generate input: job + assessment + cv_variant
const fs = require('fs');
const os = require('os');
const job = $input.first().json;

const input = JSON.stringify({
  cv_variant: job.cv_variant || 'software',
  job: `Title: ${job.title}\nCompany: ${job.company}\nLocation: ${job.location}\n\nDescription:\n${(job.description || '').substring(0, 8000)}`,
  assessment: JSON.stringify(job.assessment || {})
}, null, 2);

const tmpFile = `${os.tmpdir()}/job_generate_${Date.now()}.json`;
fs.writeFileSync(tmpFile, input);

return [{ json: { ...job, _generateInput: tmpFile } }];

// Parse generate result
const stdout = $input.first().json.stdout || '{}';
let generated;
try {
  generated = JSON.parse(stdout);
} catch(e) {
  generated = { tailored_cv_html: stdout, cover_letter_text: 'Parse error', cover_letter_html: '', tailoring_notes: e.message };
}

const jobData = $('Generate: Prep Input').first().json;
delete jobData._generateInput;

return [{
  json: {
    ...jobData,
    generated,
    tailored_cv_html: generated.tailored_cv_html || '',
    cover_letter_text: generated.cover_letter_text || '',
    cover_letter_html: generated.cover_letter_html || '',
    tailoring_notes: generated.tailoring_notes || ''
  }
}];

// Write files locally for PDF conversion and Drive upload
const fs = require('fs');
const job = $input.first().json;

const company = (job.company||'unknown').replace(/[^a-zA-Z0-9]/g,'_').substring(0,30);
const date = new Date().toISOString().split('T')[0];
const dir = `${process.env.JOBS_FUNNEL_PROJECT_DIR}/output/${date}_${company}`;

fs.mkdirSync(dir, { recursive: true });

fs.writeFileSync(`${dir}/cv.html`, job.tailored_cv_html || '');
const clHtml = job.cover_letter_html || `<html><body><pre>${job.cover_letter_text||''}</pre></body></html>`;
fs.writeFileSync(`${dir}/cover_letter.html`, clHtml);
fs.writeFileSync(`${dir}/cover_letter.txt`, job.cover_letter_text || '');
fs.writeFileSync(`${dir}/assessment.json`, JSON.stringify(job.assessment||{}, null, 2));
fs.writeFileSync(`${dir}/job.json`, JSON.stringify({
  title: job.title, company: job.company, location: job.location,
  url: job.url, description: job.description
}, null, 2));

return [{
  json: {
    ...job,
    outputDir: dir,
    folderName: `${date} ${job.company||'Unknown'} - ${job.title||'Role'}`
  }
}];

// Prepare file upload list and read files into binary
const fs = require('fs');
const dir = $('Write Local Files').first().json.outputDir;
const folderId = $input.first().json.id;

const files = [
  { path: `${dir}/cv.html`, name: 'CV.html', mime: 'text/html' },
  { path: `${dir}/cover_letter.txt`, name: 'Cover_Letter.txt', mime: 'text/plain' },
  { path: `${dir}/cover_letter.html`, name: 'Cover_Letter.html', mime: 'text/html' },
  { path: `${dir}/job.json`, name: 'Job_Posting.json', mime: 'application/json' },
  { path: `${dir}/assessment.json`, name: 'Assessment.json', mime: 'application/json' }
];

return files.map(f => {
  const fileBuffer = fs.readFileSync(f.path);
  return {
    json: { name: f.name, folderId },
    binary: {
      data: {
        data: fileBuffer.toString('base64'),
        mimeType: f.mime,
        fileName: f.name
      }
    }
  };
});
